%[text] #### Experiment 4
load("lab3_exp3_data.mat")
load("lab3_exp4_data.mat")

% Voltage Transfer Characteristic Plot + Experiment 3 Plot
% TODO: Add Fit Lines
figure() %[output:2fedee78]
hold on; %[output:2fedee78]
plot(Vin10k_e4, Vout10k_e4, '.', DisplayName='mR = 10 k\Omega; R = 1 k\Omega') %[output:2fedee78]
plot(Vin5k_e4, Vout5k_e4, '.', DisplayName='mR = 5 k\Omega; R = 1 k\Omega') %[output:2fedee78]
plot(Vin2k_e4, Vout2k_e4, '.', DisplayName='mR = 2 k\Omega; R = 1 k\Omega') %[output:2fedee78]
plot(Vin_e3, Vout_e3, '.', DisplayName='mR = 0 \Omega; R = 1 k\Omega (Experiment 3)') %[output:2fedee78]

